def date_range_filter(since: datetime | None, until: datetime | None) -> Callable[[LogEntry], bool]:
    """Match entries whose timestamp is within [since, until], either side optional."""
    def pred(entry: LogEntry) -> bool:
        if since is not None and entry.timestamp < since:
            return False
        if until is not None and entry.timestamp > until:
            return False
        return True

    return pred


def expression_filter(expr: str) -> Callable[[LogEntry], bool]:
    """Filter by a Python expression where `entry` is the LogEntry.

    Uses ast.parse to safely evaluate expressions without arbitrary code execution.
    Only allows attribute access, comparisons, arithmetic, and boolean operations.

    Examples:
        "entry.status >= 500"
        "entry.bytes > 1024 and entry.method == 'GET'"
    """
    # Pre-parse the expression to validate it's safe
    try:
        tree = ast.parse(expr, mode="eval")
    except SyntaxError as e:
        raise ValueError(f"Invalid expression: {e}") from e

    # Validate that the expression only uses safe operations
    _validate_safe_expr(tree)

    def pred(entry: LogEntry) -> bool:
        return bool(eval(compile(tree, "<expr>", "eval"), {"__builtins__": {}}, {"entry": entry}))

    return pred


def _validate_safe_expr(node: ast.AST) -> None:
    """Recursively validate that an AST node only uses safe operations.

    Raises ValueError if unsafe constructs are found.
    """
    if isinstance(node, ast.Expression):
        _validate_safe_expr(node.body)
    elif isinstance(node, ast.Attribute):
