    elif isinstance(node, ast.Call):
        raise ValueError("Function calls are not allowed in expressions")
    elif isinstance(node, ast.Subscript):
        raise ValueError("Subscript access is not allowed in expressions")
    else:
        raise ValueError(
            f"Unsupported expression node type: {type(node).__name__}"
        )


def combine_and(*preds):
    """Combine predicates with AND.

    Returns a predicate that returns True iff all predicates do.
    """
    def pred(entry: LogEntry) -> bool:
        return all(p(entry) for p in preds)

    return pred

"""Output formatters: JSON, CSV, plain text."""
from __future__ import annotations

import csv
import io
import json
from collections.abc import Iterable
from typing import Any

from .parser import LogEntry


def to_json(entries: Iterable[LogEntry]) -> str:
    """Render entries as a JSON array."""
    data = [
        {
            "ip": e.ip,
            "user": e.user,
            "timestamp": e.timestamp.isoformat(),
            "method": e.method,
            "url": e.url,
            "protocol": e.protocol,
            "status": e.status,
            "bytes": e.bytes,
        }
        for e in entries
    ]
    return json.dumps(data)


def to_csv(entries: Iterable[LogEntry]) -> str:
    """Render entries as CSV (with header row)."""
    buf = io.StringIO()
    w = csv.writer(buf)
    headers = ["ip", "user", "timestamp", "method", "url", "protocol",
               "status", "bytes"]
    w.writerow(headers)
    for e in entries:
        w.writerow([
            e.ip, e.user, e.timestamp.isoformat(),
            e.method, e.url, e.protocol, e.status, e.bytes,
        ])
    return buf.getvalue()


def to_text(entries: Iterable[LogEntry]) -> str:
    """Render entries as readable plain text, one entry per line."""
    lines = []
    for e in entries:
        lines.append(
            f"{e.timestamp.isoformat()}  {e.ip:>15}  {e.method:<6} {e.status} {e.url}"
        )
    return "\n".join(lines)


def render_aggregate(agg: Any, fmt: str = "text") -> str:
    """Render an aggregate result (Counter, dict, list) as text/json/csv."""
    if fmt == "text":
        if hasattr(agg, "items"):
            return "\n".join(f"{k}\t{v}" for k, v in agg.items())
        return "\n".join(f"{k}\t{v}" for k, v in agg)
    elif fmt == "json":
        if hasattr(agg, "items"):
            items = list(agg.items())
        else:
            items = list(agg)
        return json.dumps(dict(items))
    else:
        raise ValueError(f"unknown format: {fmt}")
